import React, { useState, useMemo } from 'react';
import JobList from '../../components/jobs/JobList';
import FilterBox from './FilterBox';
import ApplyJobForm from '../lamaran/ApplyJobForm'; // Sesuaikan path jika perlu

const JobListContainer = ({ variant = 'simple', limit }) => {
    // Simulasi data pekerjaan
    const [jobs] = useState([
        { id: 1, title: 'Fullstack Developer', company: 'PasukanYerusSolo', location: 'Solo', salary: '8jt', desc: 'Membangun arsitektur web modern.', type: 'Full-time' },
        { id: 2, title: 'React Engineer', company: 'TechEase', location: 'Jakarta', salary: '12jt', desc: 'Pengembangan UI interaktif.', type: 'Remote' },
        { id: 3, title: 'Marketing', company: 'Solopos', location: 'Solo', salary: '6jt', desc: 'Strategi konten digital.', type: 'Contract' }
    ]);

    // State untuk Filter
    const [search, setSearch] = useState('');
    const [type, setType] = useState('Semua');
    const [selectedJobId, setSelectedJobId] = useState(null); // Untuk ApplyJobForm

    // Logika Filter dan Search
    const filteredJobs = useMemo(() => {
        let result = jobs;
        if (search) {
            result = result.filter(j => 
                j.title.toLowerCase().includes(search.toLowerCase()) || 
                j.company.toLowerCase().includes(search.toLowerCase())
            );
        }
        if (type !== 'Semua') {
            result = result.filter(j => j.type === type);
        }
        return limit ? result.slice(0, limit) : result;
    }, [jobs, search, type, limit]);

    return (
        <div style={{ width: '100%' }}>
            {/* Filter hanya muncul jika variant adalah 'full' (Halaman Eksplorasi) */}
            {variant === 'full' && (
                <FilterBox 
                    appTheme="dark" 
                    isMobile={window.innerWidth < 768}
                    onSearchChange={setSearch}
                    onTypeChange={setType}
                    selectedType={type}
                />
            )}

            <JobList 
                jobs={filteredJobs} 
                variant={variant} 
                onSelectJob={(job) => setSelectedJobId(job.id)} 
            />

            {/* Jika user memilih lowongan untuk melamar */}
            {selectedJobId && (
                <div style={{ marginTop: '20px' }}>
                    <ApplyJobForm 
                        jobId={selectedJobId} 
                        onFormSuccess={() => setSelectedJobId(null)} 
                    />
                </div>
            )}
        </div>
    );
};

export default JobListContainer;
